type Profile = { name: string; avatar: string; grade: 3; createdAt: string };
type Question = { prompt: string; hint: string; options: string[]; answer: number; explanation: string };
type Activity = { id: string; week: number; title: string; subtitle: string; subject: Subject; kind: ActivityKind; minutes: number; xp: number; color: string; icon: string; questions: Question[] };
type Attempt = { score: number; total: number; completedAt: string };
type ProgressState = { xp: number; stars: number; coins: number; streak: number; completed: string[]; mastery: Record<Subject, number>; attempts: Record<string, Attempt>; diagnosticComplete: boolean; diagnosticScore: number; lastActivity: string; badges: string[] };
type Settings = { breaks: boolean; dailyLimit: number; subjects: "all" | Subject[] };

